CREATE TYPE "Role" AS ENUM ('admin','attorney','outreach_manager','intake_staff');
CREATE TYPE "Segment" AS ENUM ('founder','existing_business_contracts','trademark_brand','referral_partner','newsletter_only');
CREATE TYPE "ConsentStatus" AS ENUM ('unknown','opted_in','opted_out','existing_relationship');
CREATE TYPE "RelationshipStatus" AS ENUM ('none','existing_client','former_client','referral_partner','professional_contact');
CREATE TYPE "ConflictStatus" AS ENUM ('not_started','needs_review','cleared','conflict_found','declined');
CREATE TYPE "ApprovalStatus" AS ENUM ('draft','pending','approved','rejected');
CREATE TYPE "MessageType" AS ENUM ('cold_outreach','newsletter','resource_follow_up','transactional','legal_administrative');
CREATE TYPE "QueueStatus" AS ENUM ('draft','blocked','pending_review','approved','sent','failed','cancelled');
CREATE TYPE "Jurisdiction" AS ENUM ('NY','NJ','OTHER');

CREATE TABLE "User" ("id" TEXT PRIMARY KEY, "email" TEXT UNIQUE NOT NULL, "name" TEXT NOT NULL, "role" "Role" NOT NULL, "passwordHash" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Lead" ("id" TEXT PRIMARY KEY, "businessName" TEXT, "contactName" TEXT NOT NULL, "email" TEXT UNIQUE NOT NULL, "phone" TEXT, "website" TEXT, "state" TEXT NOT NULL, "source" TEXT, "segment" "Segment" NOT NULL, "notes" TEXT, "consentStatus" "ConsentStatus" NOT NULL DEFAULT 'unknown', "relationshipStatus" "RelationshipStatus" NOT NULL DEFAULT 'none', "doNotContact" BOOLEAN NOT NULL DEFAULT false, "unsubscribedAt" TIMESTAMP, "conflictStatus" "ConflictStatus" NOT NULL DEFAULT 'not_started', "conflictNotes" TEXT, "conflictClearedAt" TIMESTAMP, "conflictClearedById" TEXT REFERENCES "User"("id"), "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "IntakeAnswer" ("id" TEXT PRIMARY KEY, "leadId" TEXT NOT NULL REFERENCES "Lead"("id"), "businessType" TEXT, "state" TEXT NOT NULL, "legalNeedCategory" TEXT NOT NULL, "urgency" TEXT NOT NULL, "opposingParties" TEXT, "existingLawyerInvolvement" TEXT, "trademarkOrBrandName" TEXT, "contractType" TEXT, "companyStatus" TEXT, "preferredConsultationTime" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Template" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "sequenceName" TEXT, "segment" "Segment" NOT NULL, "messageType" "MessageType" NOT NULL, "jurisdiction" "Jurisdiction" NOT NULL DEFAULT 'OTHER', "subject" TEXT NOT NULL, "bodyMarkdown" TEXT NOT NULL, "lockedLegalLanguage" TEXT NOT NULL, "editableFields" JSONB NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, "status" "ApprovalStatus" NOT NULL DEFAULT 'draft', "approvedAt" TIMESTAMP, "approvedById" TEXT REFERENCES "User"("id"), "containsTestimonial" BOOLEAN NOT NULL DEFAULT false, "documentedNyException" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Campaign" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "segment" "Segment" NOT NULL, "messageType" "MessageType" NOT NULL, "status" "ApprovalStatus" NOT NULL DEFAULT 'draft', "approvedAt" TIMESTAMP, "approvedById" TEXT REFERENCES "User"("id"), "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "OutboundMessage" ("id" TEXT PRIMARY KEY, "leadId" TEXT NOT NULL REFERENCES "Lead"("id"), "templateId" TEXT NOT NULL REFERENCES "Template"("id"), "campaignId" TEXT REFERENCES "Campaign"("id"), "subjectPreview" TEXT NOT NULL, "bodyPreview" TEXT NOT NULL, "finalSubject" TEXT, "finalBody" TEXT, "templateVersion" INTEGER NOT NULL, "complianceStatus" TEXT NOT NULL, "complianceReasons" JSONB NOT NULL, "status" "QueueStatus" NOT NULL DEFAULT 'pending_review', "approvedAt" TIMESTAMP, "approvedById" TEXT REFERENCES "User"("id"), "sentAt" TIMESTAMP, "failureReason" TEXT, "providerMessageId" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ComplianceOverride" ("id" TEXT PRIMARY KEY, "targetType" TEXT NOT NULL, "targetId" TEXT NOT NULL, "reason" TEXT NOT NULL, "createdById" TEXT NOT NULL REFERENCES "User"("id"), "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ProhibitedClaim" ("id" TEXT PRIMARY KEY, "phrase" TEXT UNIQUE NOT NULL, "enabled" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AuditLog" ("id" TEXT PRIMARY KEY, "actorId" TEXT REFERENCES "User"("id"), "action" TEXT NOT NULL, "entityType" TEXT NOT NULL, "entityId" TEXT NOT NULL, "metadata" JSONB NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Resource" ("id" TEXT PRIMARY KEY, "title" TEXT NOT NULL, "segment" "Segment" NOT NULL, "markdownContent" TEXT NOT NULL, "version" INTEGER NOT NULL DEFAULT 1, "status" "ApprovalStatus" NOT NULL DEFAULT 'draft', "approvedAt" TIMESTAMP, "approvedById" TEXT REFERENCES "User"("id"), "disclaimer" TEXT NOT NULL, "versionHistory" JSONB NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "LandingPage" ("id" TEXT PRIMARY KEY, "segment" "Segment" UNIQUE NOT NULL, "headline" TEXT NOT NULL, "bodyMarkdown" TEXT NOT NULL, "resourceId" TEXT, "bookingCta" TEXT NOT NULL, "disclaimer" TEXT NOT NULL, "intakeTrigger" TEXT NOT NULL, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Consultation" ("id" TEXT PRIMARY KEY, "leadId" TEXT NOT NULL REFERENCES "Lead"("id"), "preferredTime" TEXT, "scheduledAt" TIMESTAMP, "status" TEXT NOT NULL DEFAULT 'requested', "attorneyOverrideReason" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
